import React, { useState, useEffect } from 'react';
import { api } from '../utils/api';

const sessions = ['Pre-Market', 'After-Hours', 'Both', 'Regular'];

const sessionDurations = {
  'Pre-Market': 3600 * 2, // 2 hours
  'After-Hours': 3600 * 4, // 4 hours
  Both: 3600 * 6, // 6 hours
  Regular: 3600 * 6.5, // 6.5 hours
};

function formatTime(seconds) {
  const m = Math.floor(seconds / 60)
    .toString()
    .padStart(2, '0');
  const s = (seconds % 60).toString().padStart(2, '0');
  return `${m}:${s}`;
}

const ExtendedHoursConfig = () => {
  const [extendedHoursEnabled, setExtendedHoursEnabled] = useState(false);
  const [selectedSession, setSelectedSession] = useState('Regular');
  const [bots, setBots] = useState([]);
  const [botToggles, setBotToggles] = useState({});
  const [countdown, setCountdown] = useState(sessionDurations[selectedSession]);

  useEffect(() => {
    api('/bots', { silent: true }).then(data => {
      if (data?.bots?.length > 0) {
        const names = data.bots.map(b => (b.display_name || b.bot_name || '').toUpperCase());
        setBots(names);
        const toggles = {};
        names.forEach(n => { toggles[n] = false; });
        setBotToggles(toggles);
      }
    }).catch(() => {});
  }, []);

  useEffect(() => {
    setCountdown(sessionDurations[selectedSession]);
  }, [selectedSession]);

  useEffect(() => {
    if (!extendedHoursEnabled) {
      setCountdown(sessionDurations['Regular']);
      return;
    }
    const interval = setInterval(() => {
      setCountdown((prev) => {
        if (prev <= 1) return sessionDurations[selectedSession];
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [extendedHoursEnabled, selectedSession]);

  const toggleBot = (bot) => {
    setBotToggles((prev) => ({
      ...prev,
      [bot]: !prev[bot],
    }));
  };

  return (
    <div
      style={{
        fontFamily: "'JetBrains Mono', monospace",
        backgroundColor: '#0B0F14',
        color: '#E5E7DB',
        padding: 20,
        minWidth: 320,
        borderRadius: 10,
      }}
    >
      <label
        style={{
          display: 'flex',
          alignItems: 'center',
          marginBottom: 16,
          userSelect: 'none',
          cursor: 'pointer',
        }}
      >
        <input
          type="checkbox"
          checked={extendedHoursEnabled}
          onChange={() => setExtendedHoursEnabled((v) => !v)}
          style={{ marginRight: 8, cursor: 'pointer' }}
        />
        <span style={{ fontWeight: '600', fontSize: 16 }}>Toggle Extended Hours</span>
      </label>

      <div style={{ marginBottom: 16 }}>
        {sessions.map((session) => {
          const isSelected = selectedSession === session;
          return (
            <button
              key={session}
              onClick={() => setSelectedSession(session)}
              style={{
                backgroundColor: isSelected ? '#22C55E' : '#0F1620',
                color: isSelected ? '#0B0F14' : '#E5E7DB',
                border: `1px solid #1F2A37`,
                borderRadius: 14,
                padding: '6px 14px',
                marginRight: 8,
                cursor: 'pointer',
                fontSize: 14,
                userSelect: 'none',
                transition: 'background-color 0.25s, color 0.25s',
              }}
              type="button"
            >
              {session}
            </button>
          );
        })}
      </div>

      <div
        style={{
          backgroundColor: '#F59E0B',
          color: '#0B0F14',
          padding: '10px 14px',
          borderRadius: 6,
          fontWeight: '600',
          marginBottom: 20,
          userSelect: 'none',
        }}
      >
        Amber Risk Banner: Please be aware of increased volatility during extended hours.
      </div>

      <div style={{ display: 'flex', gap: 12, marginBottom: 20, flexWrap: 'wrap' }}>
        {bots.map((bot) => (
          <div
            key={bot}
            style={{
              backgroundColor: '#0F1620',
              border: `1px solid #1F2A37`,
              borderRadius: 10,
              padding: 16,
              flex: '1 1 100px',
              minWidth: 100,
              userSelect: 'none',
            }}
          >
            <div
              style={{
                fontWeight: '700',
                fontSize: 16,
                marginBottom: 12,
                textAlign: 'center',
              }}
            >
              {bot}
            </div>
            <label
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: 'pointer',
                userSelect: 'none',
              }}
            >
              <input
                type="checkbox"
                checked={botToggles[bot]}
                onChange={() => toggleBot(bot)}
                style={{ marginRight: 8, cursor: 'pointer' }}
              />
              <span style={{ fontWeight: '600' }}>Enabled</span>
            </label>
          </div>
        ))}
      </div>

      <div
        style={{
          backgroundColor: '#0F1620',
          border: `1px solid #1F2A37`,
          borderRadius: 6,
          padding: 12,
          textAlign: 'center',
          fontWeight: '600',
          fontSize: 16,
          userSelect: 'none',
        }}
      >
        Session Status:{' '}
        <span style={{ color: extendedHoursEnabled ? '#22C55E' : '#F59E0B' }}>
          {extendedHoursEnabled ? 'Active' : 'Inactive'}
        </span>{' '}
        - Countdown: {formatTime(countdown)}
      </div>
    </div>
  );
};

export default ExtendedHoursConfig;
